        const message = choice?.message || {};
        const answer = message.content || "";
        const images = message.images; // OpenRouter возвращает массив ссылок здесь

        if (images && images.length > 0) {
            // Отправляем ПЕРВУЮ картинку из массива
            await ctx.replyWithPhoto(images[0], { caption: `Готово! 🎨\nМодель: ${modelStr}` });
            userHistory[userId].push({ role: 'assistant', content: "[Изображение]" });
        } else if (answer && (answer.startsWith('http')) && isDrawing) {
            await ctx.replyWithPhoto(answer);
            userHistory[userId].push({ role: 'assistant', content: "[Изображение по ссылке]" });
        } else if (answer) {
            userHistory[userId].push({ role: 'assistant', content: answer });
            await ctx.reply(answer);
        } else {
            throw new Error("Пустой ответ от ИИ");
        }

        storage.save(config.HISTORY_FILE, userHistory);

    } catch (e) {
        console.error('Ошибка ИИ:', e.response?.data || e.message);
        // Выводим пользователю понятную ошибку
        const errorData = e.response?.data?.error?.message || "";
        if (errorData.includes("free")) {
            await ctx.reply("❌ Эта бесплатная модель сейчас перегружена. Попробуйте другую в меню.", menus.main());
        } else {
            await ctx.reply("⚠️ Произошла ошибка при генерации. Попробуйте позже.");
        }
    }
});

// Запуск бота
bot.launch().then(() => console.log('🚀 Бот запущен!'));

// Логирование ошибок
bot.catch((err) => {
    console.error('Error in bot:', err);
});
